import Log from './Log';
import {Level} from './types';

function warn(msg:string) {
    let stack = new Error().stack;
    stack = stack.split('\n').splice(3).join('\n');
    if ((console as any).groupCollapsed) {
        (console as any).groupCollapsed("%cDeprecation Warning: %c%s", "color:#614108;background:#fffbe6", "font-weight:normal;color:#614108;background:#fffbe6", msg);
        console.warn(stack);
        console.groupEnd();
    }
    else {
        console.warn("Deprecation Warning:", msg);
        console.warn(stack);
    }
}

const LogPrototype:any = Log.prototype;

/**
 * Log to syslog
 * @method Log#toSyslog
 * @deprecated since 3.0.0
 * @see LogOutputs#syslog
 */
LogPrototype.toSyslog = function():void {
    warn('toSyslog is deprecated; please use JSON configuration');
    this.outputs.syslog = Level.debug;
};

/**
 * Log to syslog
 * @method Log#toFile
 * @deprecated since 3.0.0
 * @see LogOutputs#file
 */
LogPrototype.toFile = function(filename: string) {
    warn('toFile is deprecated, please use JSON configuration');
    this.outputs.file = Level.debug;
};

/**
 * Set minimum logging level
 * @method Log#toFile
 * @deprecated since 3.0.0
 * @see LogOutputs#all
 */
Object.defineProperty(LogPrototype, 'minLevel', {
    set(level: Level) {
      // TODO: Figure out how to properly add a property setter to an any prototype
      warn('minLevel is deprecated, please use JSON configuration');
      this.outputs.all = level;
    }
});

/**
 * Allow handling uncaught and unhandled exceptions.
 * @method Log#enableUncaughtAndUnhandled
 * @deprecated since 1.1.0
 * @see Log.logUncaughtExceptions
 * @see Log.logUnhandledRejections
 */
LogPrototype.enableUncaughtAndUnhandled = function():void {
    warn('enableUncaughtAndUnhandled is deprecated; please use JSON configuration');
    this.handleAll = true;
};

/**
 * Allow handling uncaught and unhandled exceptions.
 * @method Log#disableUncaughtAndUnhandled
 * @deprecated since 1.1.0
 * @see Log.logUncaughtExceptions
 * @see Log.logUnhandledRejections
 */
LogPrototype.disableUncaughtAndUnhandled = function():void {
    warn('enableUncaughtAndUnhandled is deprecated; please use JSON configuration');
    this.handleAll = false;
};

/**
 * Set the default logging directory.
 * @method Log#setDefaultLogDir
 * @deprecated since 1.1.0
 * @see FileConfig#filename
 */
LogPrototype.setDefaultLogDir = function(dir:string, callback?:Function):void {
    warn('setDefaultLogDir is deprecated; please use JSON configuration');
    this.defaultDir = dir;
    if (callback) {
        setImmediate(callback);
    }
};

/**
 * Allow for debug messages.
 * @method Log#enableDebug
 * @deprecated since 1.1.0
 * @see LogOutputs#all
 */
LogPrototype.enableDebug = function(name:string|RegExp, level:Level=Level.debug):void {
    warn('enableDebug is deprecated, please use JSON configuration');
    this.outputs.all = level;
};
