import * as util from 'util';
import {format} from 'format-error';

// Format the passed object for string output
const formatErrorOptions:any = {
    noColor: true
};
const inspectOptions:any = {
    depth: 3,
    maxArrayLength: 10
};

export function formatError(error:string|Error):string {
    return formatObject(format(error, formatErrorOptions));
};

export function formatObject(obj:any):string {
    return util.inspect(obj, inspectOptions);
};

/**
 * Concatenate the passed args as a single string for logging (i.e. syslog)
 * @function formatOutput
 * @param args {any[]} Arguments to Concatenate
 * @return {string} Concatenated args.
 */
export function formatOutput(args:any[]):string {
    const text: string = args.map(item =>
        typeof item === 'string' ? item :
        item instanceof Error ? formatError(item) :
        formatObject(item)
    ).join(' ').trim();
    return text;
}
