import OutputHandlerBase from './OutputHandlerBase';
import {Level} from '../types';

/**
 * Console output configuration
 * @interface ConsoleConfig
 */
interface ConsoleConfig {

    /**
     * Whether or not to add the filename and line number to each line logged
     * @name ConsoleConfig#outputFileAndLine
     * @type {boolean}
     */
    outputFileAndLine: boolean;
}

/**
 * ConsoleHandler class - logging to global.console
 * @class ConsoleHandler
 * @param {any} [_console = global.console] You may pass a alternative console
 */
class ConsoleHandler extends OutputHandlerBase<ConsoleConfig> {

    // The console configuration loaded or defaulted
    private _config: ConsoleConfig;

    constructor(private _console: any = global.console) {
        super();
    }

    /**
     * Write to the console
     * @method ConsoleHandler#write
     * @param {string} processName The name of the running process
     * @param {string} namespace The Log namespace
     * @param {Level} level The level of logging
     * @param {any[]} ...args The arguments to log
     */
    public write(
        processName: string,
        namespace: string,
        level: Level,
        ...args: any[],
    ): void {
        if(this._config && this._config.outputFileAndLine) {
            args.push(new Error().stack.split('\n')[4]);
        }
        switch(level) {
            case Level.debug:
                this._console.log(namespace, ...args);
                break;
            case Level.info:
                this._console.info(namespace, ...args);
                break;
            case Level.warn:
                this._console.warn(namespace, ...args);
                break;
            case Level.error:
                this._console.error(namespace, ...args);
                break;
        }
    }

    /**
     * The console output configuration for this handler
     * @name ConsoleHandler#config
     * @type {ConsoleConfig}
     */
    public set config(config: ConsoleConfig) {
        this._config = config;
    }
    public get config(): ConsoleConfig {
        return this._config;
    }
}

export default ConsoleHandler;

export {ConsoleConfig};
