/**
 * A logging output channel, console/syslog/file
 * @name Output
 * @type enum
 * @prop console 'console'
 * @prop syslog 'syslog'
 * @prop file 'file'
 */
type Output = 'console' | 'syslog' | 'file';
namespace Output {
    export const console: Output = 'console';
    export const syslog: Output = 'syslog';
    export const file: Output = 'file';
}

export default Output;
