import OutputHandlerBase from './OutputHandlerBase';
import {Level} from '../types';

/**
 * Enum for whether to overwrite the file, or append to it
 * @name FileWriteMode
 * @type enum
 * @prop overwrite 'overwrite'
 * @prop append 'append'
 */
type FileWriteMode = 'overwrite' | 'append';
namespace FileWriteMode {
    export const overwrite: FileWriteMode = 'overwrite';
    export const append: FileWriteMode = 'append';
}

/**
 * Filesystem output configuration
 * @interface FileConfig
 */
interface FileConfig {

    /**
     * The filename to write to write
     * @name FileConfig#filename
     * @type {string}
     */
    filename: string;

    /**
     * The mode (overwrite or append)
     * @name FileConfig#mode
     * @type {FileWriteMode}
     */
    mode: FileWriteMode;
}

/**
 * FileHandler class - logging to filesystem
 * @class FileHandler
 */
class FileHandler extends OutputHandlerBase<FileConfig> {

    // The filesystem output configuration loaded or defaulted
    private _config: FileConfig;

    /**
     * Write to the file
     * @method FileHandler#write
     * @param {string} processName The name of the running process
     * @param {string} namespace The Log namespace
     * @param {Level} level The level of logging
     * @param {any[]} ...args The arguments to log
     */
    public write(
        processName: string,
        namespace: string,
        level: Level,
        ...args: any[]
    ): void {
        return;
    }

    /**
     * The filesystem output configuration for this handler
     * @name FileHandler#config
     * @type {FileConfig}
     */
    public set config(config: FileConfig) {
        this._config = config;
    }
    public get config(): FileConfig {
        return this._config;
    }
}

export default FileHandler;

export {
    FileConfig,
    FileWriteMode
};
