/**
 * Return a list of elements from an enum, for enumerating over them
 * e.g. `for(let output in Output) { ... }`
 * @function enumerate
 * @param {any} enumType an Enum type
 * @return {Enum[]} List of elements
 */
export function enumerate<Enum>(enumType: any): Enum[] {
    return Object.keys(enumType)
        .filter(key => typeof(key) === 'string')
        .map(output => enumType[output]);
}
