/**
 * A level of logging output, debug/info/warn/error, or none
 * @typedef Level
 */
type Level = 'none' | 'debug' | 'info' | 'warn' | 'error';
namespace Level {
    export const none: Level = 'none';
    export const debug: Level = 'debug';
    export const info: Level = 'info';
    export const warn: Level = 'warn';
    export const error: Level = 'error';
}

export default Level;

export const levelOrder: Level[] = [
    Level.debug,
    Level.info,
    Level.warn,
    Level.error
];
