import OutputHandlerBase from './OutputHandlerBase';
import syslog = require('syslog-rfc5424-client');
import {Level} from '../types';
import {formatOutput} from '../utils';

/**
 * Syslog output configuration
 * @interface SyslogConfig
 */
interface SyslogConfig {

    /**
     * The port number on which to talk to syslog
     * @name SyslogConfig#port
     * @type {number}
     */
    port?: number;

    /**
     * The target hostname or IP address on which to log
     * @name SyslogConfig#target
     * @type {string}
     */
    target?: string;

    /**
     * Whether or not to add the filename and line number to each line logged
     * @name SyslogConfig#outputFileAndLine
     * @type {boolean}
     */
    outputFileAndLine?: boolean;
}

/**
 * SyslogHandler class - logging to syslog (/var/log/messages)
 * Only enabled on linux/arm (e.g. Jibo robot)
 * @class SyslogHandler
 */
class SyslogHandler extends OutputHandlerBase<SyslogConfig> {

    // Only enabled on linux/arm (e.g. Jibo robot)
    private _enabled: boolean;

    // The syslog-client used for logging
    private _client: syslog.Client;

    // The Syslog configuration loaded or defaulted
    private _config: SyslogConfig;

    constructor() {
        super();
        // don't bother on anything other than our linux/arm environment
        this._enabled = process.platform === 'linux' && process.arch === 'arm';
    }

    /**
     * Write to the log
     * @method SyslogHandler#write
     * @param {string} processName The name of the running process
     * @param {string} namespace The Log namespace
     * @param {Level} level The level of logging
     * @param {any[]} ...args The arguments to log
     */
    public write(
        processName: string,
        namespace: string,
        level: Level,
        ...args: any[],
    ): void {
        if(this._config && this._config.outputFileAndLine) {
            args.push(`\n\t${new Error().stack.split('\n')[4]}`);
        }
        // only write to syslog if it's enabled and has a client
        if(this._enabled && this._client) {
            let type: string =
                level === Level.debug ? "Debug" :
                level === Level.warn ? "Warning" :
                level === Level.error ? "Error" :
                "Informational";
            const logOptions = {
                facility: syslog.Facility.Local0,
                severity: syslog.Severity[type]
            };
            const message = `${processName} ${process.pid} - [] T.${namespace}: ${formatOutput(args)}`;
            this._client.log(message, logOptions, (error) => {
                if(error) {
                    console.error(error);
                }
            });
        }
    }

    /**
     * The syslog output configuration for this handler
     * @name SyslogHandler#config
     * @type {SyslogConfig}
     */
    public set config(config: SyslogConfig) {
        if(!this._config) {
            this._config = {};
        }
        if(config.port) {
            this._config.port = config.port;
        }
        if(config.target) {
            this._config.target = config.target;
        }
        if(config.outputFileAndLine) {
            this._config.outputFileAndLine = config.outputFileAndLine;
        }
        this._createClient();
    }
    public get config(): SyslogConfig {
        return this._config;
    }

    // Create a syslog client on the configured port and IP/hostname
    private _createClient() {
        if(this._client) {
            this._client.close();
            this._client = undefined;
        }
        if(this._enabled) {
            const options = {
                port: this._config.port,
                transport: syslog.Transport.Udp
            };
            this._client = syslog.createClient(this._config.target, options);
            console.info("Initializing a syslog client");
            this._client.on("error", function(error) {
                console.error(error);
                if(this._client) {
                    this._client.close();
                    this._client = undefined;
                }
            });
        }
    }
}

export default SyslogHandler;

export {SyslogConfig};
